// Read-only — these types define the pipeline contract

interface Signal {
  id: number;
  raw: string;
  timestamp: number;
}

interface DecodedSignal {
  id: number;
  message: string;
  receivedAt: string;
}

interface PipelineResult {
  ok: boolean;
  signal?: DecodedSignal;
  error?: string;
}

// Read-only — simulated data source

function fetchSignal(id: number): Promise<Signal> {
  return new Promise((resolve, reject) => {
    if (id <= 0) {
      reject("Invalid signal ID");
    } else {
      resolve({ id, raw: "48454C4C4F", timestamp: 1704067200 });
    }
  });
}

// Decodes a hex string to ASCII: "48454C4C4F" → "HELLO"
function decodeHex(hex: string): string {
  let result = '';
  for (let i = 0; i < hex.length; i += 2) {
    result += String.fromCharCode(parseInt(hex.substring(i, i + 2), 16));
  }
  return result;
}

// Your task: fix the three bugs in this file
// types.ts and api.ts are read-only — do not try to edit them here

function processSignal(id: number): Promise<PipelineResult> {
  try {
    const signal = await fetchSignal(id);
    const message = decodeHex(signal.id);   // Bug: wrong property
    const decoded: DecodedSignal = {
      id: signal.id,
      message,
      receivedAt: new Date(signal.timestamp).toISOString()  // Bug: wrong unit
    };
    return { ok: true, signal: decoded };
  } catch (err: unknown) {
    return { ok: false, error: String(err) };
  }
}

