// pipeline.ts — fixed

async function processSignal(id: number): Promise<PipelineResult> {
  try {
    const signal = await fetchSignal(id);
    const message = decodeHex(signal.raw);
    const decoded: DecodedSignal = {
      id: signal.id,
      message,
      receivedAt: new Date(signal.timestamp * 1000).toISOString()
    };
    return { ok: true, signal: decoded };
  } catch (err: unknown) {
    return { ok: false, error: String(err) };
  }
}
